g, b];
                let depth = vec![depth_val];

                let graded = grade_frame_cpu(
                    &pixels, &depth, 1, 1, calibration, params, true, // skip_clarity
                ).expect("grade_frame_cpu failed on synthetic pixel");

                let out = [
                    graded[0] as f32 / 255.0,
